    public static class ContactInput extends DynamicStruct {
        public String wallet;

        public String party;

        public String contactType;

        public String name;

        public String contactPerson;

        public String contactEmail;

        public String contactNumber;

        public String location;

        public String domain;

        public String accountName;

        public ContactInput(String wallet, String party, String contactType, String name, String contactPerson, String contactEmail, String contactNumber, String location, String domain, String accountName) {
            super(new org.web3j.abi.datatypes.Address(160, wallet), 
                    new org.web3j.abi.datatypes.Utf8String(party), 
                    new org.web3j.abi.datatypes.Utf8String(contactType), 
                    new org.web3j.abi.datatypes.Utf8String(name), 
                    new org.web3j.abi.datatypes.Utf8String(contactPerson), 
                    new org.web3j.abi.datatypes.Utf8String(contactEmail), 
                    new org.web3j.abi.datatypes.Utf8String(contactNumber), 
                    new org.web3j.abi.datatypes.Utf8String(location), 
                    new org.web3j.abi.datatypes.Utf8String(domain), 
                    new org.web3j.abi.datatypes.Utf8String(accountName));
            this.wallet = wallet;
            this.party = party;
            this.contactType = contactType;
            this.name = name;
            this.contactPerson = contactPerson;
            this.contactEmail = contactEmail;
            this.contactNumber = contactNumber;
            this.location = location;
            this.domain = domain;
            this.accountName = accountName;
        }

        public ContactInput(Address wallet, Utf8String party, Utf8String contactType, Utf8String name, Utf8String contactPerson, Utf8String contactEmail, Utf8String contactNumber, Utf8String location, Utf8String domain, Utf8String accountName) {
            super(wallet, party, contactType, name, contactPerson, contactEmail, contactNumber, location, domain, accountName);
            this.wallet = wallet.getValue();
            this.party = party.getValue();
            this.contactType = contactType.getValue();
            this.name = name.getValue();
            this.contactPerson = contactPerson.getValue();
            this.contactEmail = contactEmail.getValue();
            this.contactNumber = contactNumber.getValue();
            this.location = location.getValue();
            this.domain = domain.getValue();
            this.accountName = accountName.getValue();
        }
    }

